import React, { useId } from 'react';
import { Card, CardContent, Box, Typography, Stack, Chip } from '@mui/material';
import { ResponsiveChartContainer, BarPlot, ChartsXAxis, ChartsYAxis, ChartsClipPath } from '@mui/x-charts';
import response from './response.json';

interface WeeklySpending {
  day: string;
  amount: number;
}

interface CategoryBreakdown {
  category: string;
  amount: number;
}

interface ExpenseData {
  weeklySpending: WeeklySpending[];
  categoryBreakdown: CategoryBreakdown[];
}

export default function Widget() {
  const expenseData = response.data as ExpenseData;
  const clipPathId = useId();

  return (
    <Card sx={{ width: 'fit-content', minWidth: 350, maxWidth: 500, bgcolor: '#1A1A1A' }} elevation={2}>
      <CardContent sx={{ p: 2.5 }}>
        <Stack spacing={2}>
          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              Weekly Spending
            </Typography>
            <Box sx={{ width: '100%', height: 200 }}>
              <ResponsiveChartContainer
                series={[
                  {
                    type: 'bar',
                    data: expenseData.weeklySpending.map(ws => ws.amount),
                    color: '#FF5722',
                  },
                ]}
                xAxis={[
                  {
                    scaleType: 'band',
                    data: expenseData.weeklySpending.map(ws => ws.day),
                    id: 'days',
                  },
                ]}
                yAxis={[{ id: 'amount' }]}
              >
                <g clipPath={`url(#${clipPathId})`}>
                  <BarPlot />
                </g>
                <ChartsXAxis
                  axisId="days"
                  tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
                />
                <ChartsYAxis
                  axisId="amount"
                  tickLabelStyle={{ fontSize: 10, fill: '#FFFFFF' }}
                />
                <ChartsClipPath id={clipPathId} />
              </ResponsiveChartContainer>
            </Box>
          </Box>

          <Box>
            <Typography variant="h6" sx={{ color: '#FFC107', mb: 1 }}>
              Category Breakdown
            </Typography>
            <Stack direction="row" spacing={0.5}>
              {expenseData.categoryBreakdown.map((category, index) => (
                <Chip
                  key={index}
                  label={`${category.category}: $${category.amount.toFixed(2)}`}
                  sx={{ fontSize: '11px', bgcolor: '#333333', color: '#FFC107' }}
                />
              ))}
            </Stack>
          </Box>
        </Stack>
      </CardContent>
    </Card>
  );
}
